const { Pool } = require('./node_modules/pg');
const pool = new Pool({ connectionString: 'postgresql://postgres@/postgres' });
async function run() {
  for (let i = 0; i < 5; i++) {
    const start = Date.now();
    await pool.query(\"SELECT * FROM app.orders WHERE created_at >= '2025-02-01' AND created_at < '2025-03-01' ORDER BY created_at\");
    console.log('Run', i+1, ':', Date.now() - start, 'ms');
  }
  await pool.end();
}
run();
"

